export enum UserRole {
  PERSONAL = 'PERSONAL',
  BUSINESS = 'BUSINESS',
  ADMIN = 'ADMIN'
}

export enum UserStatus {
  ACTIVE = 'ACTIVE',
  LOCKED = 'LOCKED'
}

export interface Transaction {
  id: string;
  type: 'DEBIT' | 'CREDIT';
  amount: number;
  category: string;
  description: string;
  date: string;
  to?: string;
  from?: string;
}

export interface Loan {
  id: string;
  userId: string;
  userName: string;
  amount: number;
  term: number; // months
  status: 'PENDING' | 'APPROVED' | 'REJECTED';
  date: string;
}

export interface SubAccount {
  id: string;
  name: string;
  balance: number;
  type: 'SAVINGS' | 'CHECKING' | 'PAYROLL';
}

export interface User {
  id: string;
  username: string;
  name: string;
  role: UserRole;
  status: UserStatus;
  balance: number;
  transactions: Transaction[];
  loans: Loan[];
  subAccounts?: SubAccount[];
  failedLoginAttempts: number;
}

export interface BankState {
  currentUser: User | null;
  allUsers: User[];
  enterpriseDemoMode: boolean;
  language: 'EN' | 'ES' | 'FR';
}

export type Action =
  | { type: 'LOGIN'; payload: User }
  | { type: 'LOGOUT' }
  | { type: 'UPDATE_USER'; payload: User }
  | { type: 'TOGGLE_DEMO_MODE' }
  | { type: 'SET_LANGUAGE'; payload: 'EN' | 'ES' | 'FR' }
  | { type: 'APPROVE_LOAN'; payload: { loanId: string; userId: string } }
  | { type: 'REJECT_LOAN'; payload: { loanId: string; userId: string } }
  | { type: 'LOCK_USER'; payload: string }
  | { type: 'UNLOCK_USER'; payload: string }
  | { type: 'ADMIN_UPDATE_BALANCE'; payload: { userId: string; newBalance: number } };

import React, { createContext, useContext, useReducer, useEffect, ReactNode } from 'react';
import { BankState, Action, User, UserRole, UserStatus, Transaction, Loan } from '../types';
import { INITIAL_USERS } from '../constants';

const initialState: BankState = {
  currentUser: null,
  allUsers: INITIAL_USERS,
  enterpriseDemoMode: false,
  language: 'EN'
};

const BankContext = createContext<{
  state: BankState;
  dispatch: React.Dispatch<Action>;
} | undefined>(undefined);

function bankReducer(state: BankState, action: Action): BankState {
  switch (action.type) {
    case 'LOGIN':
      return { ...state, currentUser: action.payload };
    case 'LOGOUT':
      return { ...state, currentUser: null };
    case 'TOGGLE_DEMO_MODE':
      return { ...state, enterpriseDemoMode: !state.enterpriseDemoMode };
    case 'SET_LANGUAGE':
      return { ...state, language: action.payload };
    case 'UPDATE_USER':
      const updatedAllUsers = state.allUsers.map(u => u.id === action.payload.id ? action.payload : u);
      return {
        ...state,
        allUsers: updatedAllUsers,
        currentUser: state.currentUser?.id === action.payload.id ? action.payload : state.currentUser
      };
    case 'APPROVE_LOAN':
      return {
        ...state,
        allUsers: state.allUsers.map(u => {
          if (u.id === action.payload.userId) {
            const loanIndex = u.loans.findIndex(l => l.id === action.payload.loanId);
            if (loanIndex !== -1) {
              const updatedLoans = [...u.loans];
              const loan = updatedLoans[loanIndex];
              updatedLoans[loanIndex] = { ...loan, status: 'APPROVED' };
              const newBalance = u.balance + loan.amount;
              const newTransaction: Transaction = {
                id: `t-loan-${Date.now()}`,
                type: 'CREDIT',
                amount: loan.amount,
                category: 'Loan',
                description: `Loan ${loan.id} Disbursement`,
                date: new Date().toISOString().split('T')[0]
              };
              return { ...u, balance: newBalance, loans: updatedLoans, transactions: [newTransaction, ...u.transactions] };
            }
          }
          return u;
        }),
        currentUser: state.currentUser // Admin remains current user
      };
    case 'REJECT_LOAN':
      return {
        ...state,
        allUsers: state.allUsers.map(u => {
          if (u.id === action.payload.userId) {
            const updatedLoans = u.loans.map(l => l.id === action.payload.loanId ? { ...l, status: 'REJECTED' as const } : l);
            return { ...u, loans: updatedLoans };
          }
          return u;
        })
      };
    case 'LOCK_USER':
      return {
        ...state,
        allUsers: state.allUsers.map(u => u.id === action.payload ? { ...u, status: UserStatus.LOCKED } : u)
      };
    case 'UNLOCK_USER':
      return {
        ...state,
        allUsers: state.allUsers.map(u => u.id === action.payload ? { ...u, status: UserStatus.ACTIVE } : u)
      };
    case 'ADMIN_UPDATE_BALANCE':
      return {
        ...state,
        allUsers: state.allUsers.map(u => u.id === action.payload.userId ? { ...u, balance: action.payload.newBalance } : u)
      };
    default:
      return state;
  }
}

export const BankProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [state, dispatch] = useReducer(bankReducer, initialState);

  // Sync currentUser with updated data from allUsers
  useEffect(() => {
    if (state.currentUser) {
      const refreshedUser = state.allUsers.find(u => u.id === state.currentUser?.id);
      if (refreshedUser && JSON.stringify(refreshedUser) !== JSON.stringify(state.currentUser)) {
        // Only update if data actually changed to avoid loop
        // We use state updates within reducer mostly, but if we need a refresh:
      }
    }
  }, [state.allUsers, state.currentUser]);

  return (
    <BankContext.Provider value={{ state, dispatch }}>
      {children}
    </BankContext.Provider>
  );
};

export const useBank = () => {
  const context = useContext(BankContext);
  if (!context) throw new Error('useBank must be used within a BankProvider');
  return context;
};

import React, { useEffect } from 'react';
import { CheckCircle, XCircle, Info, AlertTriangle } from 'lucide-react';

interface ToastProps {
  message: string;
  type: 'success' | 'error' | 'info' | 'warning';
  onClose: () => void;
}

export const Toast: React.FC<ToastProps> = ({ message, type, onClose }) => {
  useEffect(() => {
    const timer = setTimeout(onClose, 4000);
    return () => clearTimeout(timer);
  }, [onClose]);

  const icons = {
    success: <CheckCircle className="text-emerald-400" />,
    error: <XCircle className="text-red-400" />,
    info: <Info className="text-blue-400" />,
    warning: <AlertTriangle className="text-yellow-400" />,
  };

  const borderColors = {
    success: 'border-emerald-500',
    error: 'border-red-500',
    info: 'border-blue-500',
    warning: 'border-yellow-500',
  };

  return (
    <div className={`fixed top-4 right-4 glass ${borderColors[type]} border-l-4 p-4 rounded-lg shadow-2xl flex items-center space-x-3 z-50 animate-slide-in`}>
      {icons[type]}
      <span className="text-sm font-medium">{message}</span>
      <button onClick={onClose} className="opacity-50 hover:opacity-100">&times;</button>
    </div>
  );
};

export const useToast = () => {
  const [toast, setToast] = React.useState<{ message: string; type: 'success' | 'error' | 'info' | 'warning' } | null>(null);

  const showToast = (message: string, type: 'success' | 'error' | 'info' | 'warning' = 'info') => {
    setToast({ message, type });
  };

  const ToastContainer = toast ? (
    <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />
  ) : null;

  return { showToast, ToastContainer };
};

