                            value={newBalance}
                            onChange={(e) => setNewBalance(e.target.value)}
                            onBlur={() => handleUpdateBalance(u.id)}
                            autoFocus
                          />
                        </div>
                      ) : (
                        `$${u.balance.toLocaleString()}`
                      )}
                    </td>
                    <td className="py-4">
                      <span className={`text-[10px] font-bold ${u.status === UserStatus.ACTIVE ? 'emerald-text' : 'text-red-400'}`}>{u.status}</span>
                    </td>
                    <td className="py-4 text-right">
                      <div className="flex items-center justify-end space-x-2">
                        {u.status === UserStatus.ACTIVE ? (
                          <button onClick={() => dispatch({ type: 'LOCK_USER', payload: u.id })} className="p-2 hover:bg-red-500/10 text-red-400 rounded-lg transition-all" title="Lock Account"><Lock size={16} /></button>
                        ) : (
                          <button onClick={() => dispatch({ type: 'UNLOCK_USER', payload: u.id })} className="p-2 hover:bg-emerald-500/10 emerald-text rounded-lg transition-all" title="Unlock Account"><Unlock size={16} /></button>
                        )}
                        <button onClick={() => { setSelectedUserId(u.id); setNewBalance(u.balance.toString()); }} className="p-2 hover:bg-white/10 text-white/50 hover:text-white rounded-lg transition-all"><Edit3 size={16} /></button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>

        {/* Pending Requests */}
        <div className="glass p-6 rounded-3xl">
          <h3 className="font-bold mb-6 flex items-center space-x-2"><AlertCircle size={20} className="text-yellow-400" /> <span>Credit Approvals</span></h3>
          <div className="space-y-4">
            {pendingLoans.length > 0 ? pendingLoans.map(loan => (
              <div key={loan.id} className="p-4 bg-white/5 border border-white/10 rounded-2xl relative group">
                <div className="flex justify-between items-start mb-2">
                  <div>
                    <p className="text-xs text-white/40 font-bold uppercase">{loan.userName}</p>
                    <p className="text-lg font-bold">${loan.amount.toLocaleString()}</p>
                  </div>
                  <span className="text-[10px] bg-yellow-500/20 text-yellow-500 px-2 py-1 rounded-full font-bold">PENDING</span>
                </div>
                <p className="text-xs text-white/60 mb-4">{loan.term} Months / Fixed Interest</p>
                <div className="flex space-x-2">
                  <button 
                    onClick={() => dispatch({ type: 'APPROVE_LOAN', payload: { loanId: loan.id, userId: loan.userId } })}
                    className="flex-1 bg-emerald-500 hover:bg-emerald-600 text-[#0B1C2D] font-bold py-2 rounded-xl transition-all flex items-center justify-center space-x-1"
                  >
                    <Check size={16} /> <span>Approve</span>
                  </button>
                  <button 
                    onClick={() => dispatch({ type: 'REJECT_LOAN', payload: { loanId: loan.id, userId: loan.userId } })}
                    className="p-2 bg-red-500/20 hover:bg-red-500/40 text-red-400 rounded-xl transition-all"
                  >
                    <X size={16} />
                  </button>
                </div>
              </div>
            )) : (
              <div className="py-12 text-center">
                <p className="text-white/20 italic">No pending credit requests</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { BankProvider, useBank } from './context/BankContext';
import { UserRole, UserStatus, Transaction, Loan } from './types';
import { Layout } from './components/Layout';
import { PersonalDashboard } from './components/Dashboard/PersonalDashboard';
import { BusinessDashboard } from './components/Dashboard/BusinessDashboard';
import { AdminDashboard } from './components/Dashboard/AdminDashboard';
import { TransferModal, LoanModal } from './components/Modals';
import { useToast } from './components/Toast';
import { ShieldCheck, Lock, ArrowRight } from 'lucide-react';

const LoginPage: React.FC = () => {
  const { state, dispatch } = useBank();
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const { showToast, ToastContainer } = useToast();

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    setTimeout(() => {
      const user = state.allUsers.find(u => u.username === username);
      // Premium ACCOUNTS Logic: Password is username + "01"
      if (user && password === `${username}01`) {
        dispatch({ type: 'LOGIN', payload: user });
        showToast(`Welcome, ${user.name}`, 'success');
      } else {
        showToast('Invalid credentials. Please check your clearance.', 'error');
      }
      setLoading(false);
    }, 1200);
  };

  return (
    <div className="min-h-screen flex items-center justify-center p-6 bg-[#0B1C2D] relative overflow-hidden">
      {ToastContainer}
      {/* Decorative Gradients */}
      <div className="absolute top-0 -left-1/4 w-[500px] h-[500px] bg-gold-bg/10 rounded-full blur-[120px]" />
      <div className="absolute bottom-0 -right-1/4 w-[500px] h-[500px] bg-blue-500/10 rounded-full blur-[120px]" />

      <div className="w-full max-w-md relative z-10">
        <div className="text-center mb-10">
          <div className="w-16 h-16 gold-bg rounded-2xl mx-auto flex items-center justify-center font-bold text-[#0B1C2D] text-3xl mb-4 shadow-2xl">A</div>
          <h1 className="text-3xl font-bold tracking-tight">Aureon<span className="gold-text">Bank</span></h1>
          <p className="text-white/40 mt-2 font-medium">Digital Banking, Elevated.</p>
        </div>

        <form onSubmit={handleLogin} className="glass p-8 rounded-3xl border-white/5 shadow-2xl space-y-6">
          <div className="space-y-2">
            <label className="text-xs font-bold text-white/40 uppercase tracking-widest ml-1">Username</label>
            <input 
              type="text" required value={username} onChange={e => setUsername(e.target.value)}
              className="w-full bg-white/5 border border-white/10 rounded-xl p-4 focus:border-gold-bg outline-none transition-all"
              placeholder="Premium Identity"
            />
          </div>
          <div className="space-y-2">
            <label className="text-xs font-bold text-white/40 uppercase tracking-widest ml-1">Password</label>
            <input 
              type="password" required value={password} onChange={e => setPassword(e.target.value)}
              className="w-full bg-white/5 border border-white/10 rounded-xl p-4 focus:border-gold-bg outline-none transition-all"
              placeholder="••••••••"
            />
          </div>
          <button 
            type="submit" disabled={loading}
            className="w-full gold-bg text-[#0B1C2D] font-bold py-4 rounded-xl hover:scale-[1.02] active:scale-[0.98] transition-all flex items-center justify-center space-x-2"
          >
            {loading ? 'Verifying Identity...' : (
              <>
                <span>Access Terminal</span>
                <ArrowRight size={20} />
              </>
            )}
          </button>
          <div className="pt-4 text-center">
            <p className="text-[10px] text-white/20 uppercase tracking-[0.2em] font-bold flex items-center justify-center space-x-1">
              <ShieldCheck size={12} />
              <span>AES-256 Encrypted Session</span>
            </p>
